// Configuración: dominios a trackear y su nombre legible para el dashboard.
// Para sumar/sacar competidores, editá este array.

const COMPETIDORES = [
  { competidor: 'Drean',          dominio: 'drean.com.ar',            es_propio: true  },
  { competidor: 'Electrolux',     dominio: 'tienda.electrolux.com.ar', es_propio: false },
  { competidor: 'Gafa',           dominio: 'tienda.gafa.com.ar',       es_propio: false },
  { competidor: 'Philco',         dominio: 'philco.com.ar',            es_propio: false },
  { competidor: 'Philco (Newsan)',dominio: 'tiendanewsan.com.ar',      es_propio: false },
  { competidor: 'Whirlpool',      dominio: 'whirlpool.com.ar',         es_propio: false },
];

return [{
  json: {
    competidores: COMPETIDORES,
    fecha: new Date().toISOString().slice(0, 10),
  },
}];

// Normaliza la respuesta del actor SimilarWeb a filas para la tabla
// competitor_web de Supabase.
//
// El actor de SimilarWeb devuelve por dominio un objeto con campos como:
//   - name (dominio)
//   - totalVisits / monthlyVisits (visitas estimadas)
//   - uniqueVisitors
//   - bounceRate, pagesPerVisit, avgVisitDuration
//   - trafficSources / engagements.trafficSources (objeto con %)
//   - topPages / pages (array)
//   - topCountries / countries (array)
//   - topKeywords / keywords (array)
//
// Los nombres de campo varían entre actors. El normalize de abajo intenta
// múltiples claves para cada métrica.

const items = $input.all();
const config = $('Set Config').first().json;
const fecha = config.fecha;

// Mapa dominio → metadata (competidor name, es_propio)
const metaByDominio = {};
for (const c of config.competidores) {
  metaByDominio[c.dominio.toLowerCase()] = c;
}

const pick = (obj, keys) => {
  for (const k of keys) {
    if (obj?.[k] !== undefined && obj?.[k] !== null) return obj[k];
  }
  return null;
};

const toInt = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? Math.round(n) : null;
};

const toFloat = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const output = [];
for (const item of items) {
  const r = item.json;
  const dominio = String(pick(r, ['name', 'domain', 'website', 'siteName']) || '').toLowerCase().replace(/^https?:\/\//, '').replace(/\/+$/, '');
  if (!dominio) continue;

  const meta = metaByDominio[dominio] || { competidor: dominio, es_propio: false };

  output.push({
    json: {
      fecha,
      competidor: meta.competidor,
      dominio,
      visitas_estimadas: toInt(pick(r, ['totalVisits', 'monthlyVisits', 'visits', 'estimatedVisits'])),
      visitantes_unicos: toInt(pick(r, ['uniqueVisitors', 'monthlyUniqueVisitors'])),
      bounce_rate: toFloat(pick(r, ['bounceRate', 'bounce_rate'])),
      pages_per_visit: toFloat(pick(r, ['pagesPerVisit', 'pages_per_visit', 'pagesPerView'])),
      avg_visit_duration: toFloat(pick(r, ['avgVisitDuration', 'avg_visit_duration', 'averageVisitDuration'])),
      fuentes_trafico: pick(r, ['trafficSources', 'sources', 'engagements']) || null,
      paginas_top: pick(r, ['topPages', 'pages', 'mostPopularPages']) || null,
      paises_top: pick(r, ['topCountries', 'countries', 'geography']) || null,
      keywords_top: pick(r, ['topKeywords', 'keywords', 'organicKeywords']) || null,
      source: 'apify_similarweb',
      raw: r,
    },
  });
}

return output;
